// Simple Factory — Notification System
// Edit this code, hit Run, and watch the tests pass!

interface Notification {
    void send(String message);
    String getType();
}

class EmailNotification implements Notification {
    public void send(String message) {
        System.out.println("[EMAIL] Sending: " + message);
    }
    public String getType() { return "email"; }
}

class SMSNotification implements Notification {
    public void send(String message) {
        System.out.println("[SMS] Sending: " + message);
    }
    public String getType() { return "sms"; }
}

class PushNotification implements Notification {
    public void send(String message) {
        System.out.println("[PUSH] Sending: " + message);
    }
    public String getType() { return "push"; }
}

class NotificationFactory {
    public static Notification create(String type) {
        switch (type.toLowerCase()) {
            case "email": return new EmailNotification();
            case "sms":   return new SMSNotification();
            case "push":  return new PushNotification();
            default: throw new IllegalArgumentException("Unknown type: " + type);
        }
    }
}

public class Main {
    public static void main(String[] args) {
        // Test 1: Create each type
        Notification email = NotificationFactory.create("email");
        Notification sms = NotificationFactory.create("sms");
        Notification push = NotificationFactory.create("push");

        // Test 2: Send messages
        email.send("Order confirmed!");
        sms.send("Your OTP is 4829");
        push.send("Flash sale starts now!");

        // Test 3: Verify types
        System.out.println("Type: " + email.getType());
        System.out.println("Type: " + sms.getType());
        System.out.println("Type: " + push.getType());

        System.out.println("ALL TESTS PASSED");
    }
}

// Registry Factory — Zero switch, zero if-else
import java.util.*;
import java.util.function.Supplier;

interface Notification {
    void send(String message);
    String getType();
}

class EmailNotification implements Notification {
    public void send(String message) {
        System.out.println("[EMAIL] " + message);
    }
    public String getType() { return "email"; }
}

class SMSNotification implements Notification {
    public void send(String message) {
        System.out.println("[SMS] " + message);
    }
    public String getType() { return "sms"; }
}

class PushNotification implements Notification {
    public void send(String message) {
        System.out.println("[PUSH] " + message);
    }
    public String getType() { return "push"; }
}

class NotificationFactory {
    private static final Map<String, Supplier<Notification>> registry
        = new HashMap<>();

    static {
        register("email", EmailNotification::new);
        register("sms", SMSNotification::new);
        register("push", PushNotification::new);
    }

    public static void register(String type, Supplier<Notification> creator) {
        registry.put(type.toLowerCase(), creator);
    }

    public static Notification create(String type) {
        Supplier<Notification> creator = registry.get(type.toLowerCase());
        if (creator == null) {
            throw new IllegalArgumentException(
                "Unknown type: " + type + ". Available: " + registry.keySet());
        }
        return creator.get();
    }

    public static Set<String> getRegisteredTypes() {
        return Collections.unmodifiableSet(registry.keySet());
    }
}

public class Main {
    public static void main(String[] args) {
        // Test existing types
        NotificationFactory.create("email").send("Welcome!");
        NotificationFactory.create("sms").send("OTP: 1234");
        NotificationFactory.create("push").send("New message");

        // Show registered types
        System.out.println("Registered: " + NotificationFactory.getRegisteredTypes());

        // RUNTIME registration — no Factory code changes!
        NotificationFactory.register("whatsapp", () -> new Notification() {
            public void send(String msg) { System.out.println("[WHATSAPP] " + msg); }
            public String getType() { return "whatsapp"; }
        });

        NotificationFactory.create("whatsapp").send("Runtime registration works!");
        System.out.println("After registration: " + NotificationFactory.getRegisteredTypes());

        System.out.println("REGISTRY TESTS PASSED");
    }
}

// Abstract Factory — Regional Compliance Families
import java.util.*;

// Product interfaces — the FAMILY
interface TaxCalculator {
    double calculate(double amount);
    String getDescription();
}

interface CurrencyFormatter {
    String format(double amount);
}

interface ReceiptGenerator {
    String generate(List<String> items, double total, double tax);
}

// India family
class GSTCalculator implements TaxCalculator {
    public double calculate(double amount) { return amount * 0.18; }
    public String getDescription() { return "GST 18%"; }
}

class RupeeFormatter implements CurrencyFormatter {
    public String format(double amount) {
        return String.format("Rs. %.2f", amount);
    }
}

class IndiaReceiptGenerator implements ReceiptGenerator {
    public String generate(List<String> items, double total, double tax) {
        return "=== INDIAN TAX INVOICE ===\n"
            + "Items: " + items + "\n"
            + "Subtotal: Rs. " + String.format("%.2f", total) + "\n"
            + "GST (18%): Rs. " + String.format("%.2f", tax) + "\n"
            + "Total: Rs. " + String.format("%.2f", total + tax) + "\n"
            + "GSTIN: 27AABCU9603R1ZJ";
    }
}

// US family
class SalesTaxCalculator implements TaxCalculator {
    public double calculate(double amount) { return amount * 0.0825; }
    public String getDescription() { return "Sales Tax 8.25%"; }
}

class DollarFormatter implements CurrencyFormatter {
    public String format(double amount) {
        return String.format("$%.2f", amount);
    }
}

class USReceiptGenerator implements ReceiptGenerator {
    public String generate(List<String> items, double total, double tax) {
        return "=== US RECEIPT ===\n"
            + "Items: " + items + "\n"
            + "Subtotal: $" + String.format("%.2f", total) + "\n"
            + "Tax (8.25%): $" + String.format("%.2f", tax) + "\n"
            + "Total: $" + String.format("%.2f", total + tax);
    }
}

// Abstract Factory
interface RegionalComplianceFactory {
    TaxCalculator createTaxCalculator();
    CurrencyFormatter createCurrencyFormatter();
    ReceiptGenerator createReceiptGenerator();
}

class IndiaComplianceFactory implements RegionalComplianceFactory {
    public TaxCalculator createTaxCalculator() { return new GSTCalculator(); }
    public CurrencyFormatter createCurrencyFormatter() { return new RupeeFormatter(); }
    public ReceiptGenerator createReceiptGenerator() { return new IndiaReceiptGenerator(); }
}

class USComplianceFactory implements RegionalComplianceFactory {
    public TaxCalculator createTaxCalculator() { return new SalesTaxCalculator(); }
    public CurrencyFormatter createCurrencyFormatter() { return new DollarFormatter(); }
    public ReceiptGenerator createReceiptGenerator() { return new USReceiptGenerator(); }
}

// Client — knows NOTHING about India or US
class CheckoutService {
    private final TaxCalculator tax;
    private final CurrencyFormatter currency;
    private final ReceiptGenerator receipt;

    CheckoutService(RegionalComplianceFactory factory) {
        this.tax = factory.createTaxCalculator();
        this.currency = factory.createCurrencyFormatter();
        this.receipt = factory.createReceiptGenerator();
    }

    void checkout(List<String> items, double subtotal) {
        double taxAmount = tax.calculate(subtotal);
        String total = currency.format(subtotal + taxAmount);
        System.out.println(receipt.generate(items, subtotal, taxAmount));
        System.out.println("Charged: " + total);
        System.out.println("Tax type: " + tax.getDescription());
    }
}

public class Main {
    public static void main(String[] args) {
        List<String> items = Arrays.asList("Laptop", "Mouse", "Keyboard");

        System.out.println("--- INDIA ORDER ---");
        CheckoutService indiaCheckout = new CheckoutService(new IndiaComplianceFactory());
        indiaCheckout.checkout(items, 1000.00);

        System.out.println();

        System.out.println("--- US ORDER ---");
        CheckoutService usCheckout = new CheckoutService(new USComplianceFactory());
        usCheckout.checkout(items, 1000.00);

        System.out.println("\nABSTRACT FACTORY TESTS PASSED");
    }
}
